UPDATE dishes SET recipe = '晚粳米浸泡磨浆压制成年糕。可切片与蔬菜肉类同炒，或放入汤中煮食，口感软糯弹牙，是宁波传统节令食品。' WHERE id = 'zhejiang_ningbo_niangao';
UPDATE dishes SET recipe = '黑芝麻炒香碾碎，加猪油和白糖拌匀做馅。糯米粉加水揉成面团，包入馅料搓圆，下入沸水中煮至浮起即熟。' WHERE id = 'zhejiang_ningbo_tangyuan';
UPDATE dishes SET recipe = '面条入沸水煮至八成熟捞出。锅中炒香雪菜和笋片，放入瘦肉片翻炒，加汤烧开后下面条煮熟，调味即成。' WHERE id = 'zhejiang_pianerchuan';
UPDATE dishes SET recipe = '面粉和面擀薄，包入猪肉辣椒葱花馅，收口按扁成饼状。放入烤炉中烤至两面金黄酥脆，取出趁热食用，香辣可口。' WHERE id = 'zhejiang_quzhou_kaobing';
UPDATE dishes SET recipe = '兔头、鸭头、鱼头和鸭掌洗净焯水。锅中热油炒香辣椒等调料，放入主料加水和酱油，大火烧开转小火焖煮至入味酥烂即成。' WHERE id = 'zhejiang_quzhou_santou';
UPDATE dishes SET recipe = '豆腐放入特制卤水中浸泡发酵至入味变臭。捞出沥干，放入七成热油中炸至外皮金黄酥脆，捞出配辣椒酱和甜面酱食用。' WHERE id = 'zhejiang_shaoxing_chou_doufu';
UPDATE dishes SET recipe = '三黄鸡处理干净，放入加了绍兴黄酒、枸杞和姜片的水中煮熟。捞出斩块，淋上热黄酒汁，上锅蒸十分钟入味即成。' WHERE id = 'zhejiang_shaoxing_huangjiu_ji';
UPDATE dishes SET recipe = '三黄鸡煮熟捞出斩块，用绍兴黄酒、枸杞和姜浸泡。放入冰箱冷藏腌制数小时至入味，取出食用酒香浓郁、鸡肉鲜嫩。' WHERE id = 'zhejiang_shaoxing_mifan';
UPDATE dishes SET recipe = '面粉和面擀成薄皮，猪肉加猪皮冻拌馅。包入薄皮中捏出褶子，上笼大火蒸八分钟至皮透馅熟，汤汁饱满即成。' WHERE id = 'zhejiang_shengzhou_xiaolong';
UPDATE dishes SET recipe = '面粉薄饼摊平，依次铺上炒好的肉丝、鸡蛋丝、豆腐干丝、豆芽和粉条。卷成筒状，放平底锅中煎至两面金黄即成。' WHERE id = 'zhejiang_taizhou_bingtong';
UPDATE dishes SET recipe = '老姜切片加水熬成浓姜汤，虾干和香菇泡发。姜汤烧开下面条煮熟，加入虾干、香菇和青菜，打入鸡蛋煮至凝固即成。' WHERE id = 'zhejiang_taizhou_jiangtang_mian';
UPDATE dishes SET recipe = '糯米蒸熟后捣成糍粑状，趁热揪成小团。放入红糖水中煮至浮起，捞出裹上芝麻和黄豆粉，软糯香甜即成。' WHERE id = 'zhejiang_taizhou_xianju_mifan';
UPDATE dishes SET recipe = '大米和黄豆磨成浆做外皮，猪肉萝卜丝做馅。将浆倒入灯盏形模具中，放入馅料再覆一层浆，入油锅炸至金黄酥脆即成。' WHERE id = 'zhejiang_wenzhou_dengzhan_gao';
UPDATE dishes SET recipe = '鸭舌洗净焯水，锅中放酱油、冰糖、八角和桂皮加水烧开。放入鸭舌小火焖煮至入味收汁，晾凉后食用，酱香浓郁。' WHERE id = 'zhejiang_wenzhou_yashe';
UPDATE dishes SET recipe = '鮸鱼取肉剁成鱼泥，加淀粉、葱姜水搅拌上劲。将鱼泥挤成丸子状放入沸水中煮至浮起，加盐调味，鱼丸弹牙鲜嫩。' WHERE id = 'zhejiang_wenzhou_yumian';
UPDATE dishes SET recipe = '草鱼处理干净入沸水中煮至刚熟，捞出摆盘。锅中加糖、醋和姜末熬成浓稠糖醋汁，均匀浇在鱼身上即成。' WHERE id = 'zhejiang_xihu_cuyu';
UPDATE dishes SET recipe = '小黄鱼煎至两面金黄，虾和蛤蜊焯水备用。锅中加水烧开下面条煮熟，放入海鲜和青菜煮至入味，加盐调味即成。' WHERE id = 'zhejiang_zhoushan_haixian';
